async (page) => {
  // Walk south first to get around the wall structure
  const result1 = await page.evaluate(({x, y}) => JSON.stringify(window.__clickTile(x, y)), {x: 326, y: 893});
  await page.waitForTimeout(2000);
  const result2 = await page.evaluate(({x, y}) => JSON.stringify(window.__clickTile(x, y)), {x: 323, y: 893});
  await page.waitForTimeout(2000);
  const pos = await page.evaluate(() => {
    const s = window.__latestGameState;
    return s ? {x: s.player_position.x, y: s.player_position.y} : null;
  });
  return JSON.stringify({result1, result2, pos});
}

