async (page) => {
  // Walk south toward the beach
  const result = await page.evaluate(({x, y}) => JSON.stringify(window.__clickTile(x, y)), {x: 199, y: 185});
  await page.waitForTimeout(4000);

  const pos = await page.evaluate(() => {
    const s = window.__latestGameState;
    return {pos: s.player_position, items: s.nearby_entities.filter(e => e.type === 4).map(e => `${e.name}(${e.x},${e.y})d=${e.distance}`)};
  });
  return JSON.stringify(pos);
}

async (page) => {
  // Attack the Rat (E0 - already damaged)
  const result = await page.evaluate((label) => JSON.stringify(window.__clickEntity(label)), 'E0');
  await page.waitForTimeout(6000);

  const state = await page.evaluate(() => {
    const s = window.__latestGameState;
    return {
      pos: s.player_position,
      hp: `${s.player_stats.hp}/${s.player_stats.max_hp}`,
      level: s.player_stats.level,
      exp: s.player_stats.experience,
      last_xp: s.last_xp_event,
      nearby_mobs: s.nearby_entities.filter(e => e.type === 3).slice(0,5).map(e => `${e.name}@(${e.x},${e.y})hp=${e.hp}d=${e.distance}`)
    };
  });
  return JSON.stringify(state);
}
